class Solution {
    public int lastStoneWeight(int[] stones) {
        java.util.List<Integer> list = new java.util.ArrayList<>();
        for (int s : stones) list.add(s);

        while (list.size() > 1) {
            java.util.Collections.sort(list, java.util.Collections.reverseOrder());
            int first = list.remove(0);
            int second = list.remove(0);
            if (first != second) list.add(first - second);
        }
        return list.isEmpty() ? 0 : list.get(0);
    }
}

class Solution {
    public int lastStoneWeight(int[] stones) {
        java.util.PriorityQueue<Integer> maxHeap = new java.util.PriorityQueue<>(java.util.Collections.reverseOrder());
        for (int s : stones) maxHeap.offer(s);

        while (maxHeap.size() > 1) {
            int first = maxHeap.poll();
            int second = maxHeap.poll();
            if (first != second) maxHeap.offer(first - second);
        }
        return maxHeap.isEmpty() ? 0 : maxHeap.poll();
    }
}

